// Run this ONCE in your browser console or as a Next.js API route
// to seed the debates and positions tables.
// 
// Easiest way: paste in browser console on historyoptional.xyz
// (so supabase client is already loaded)

const SEED = [{"title":"Indian Feudalism Debate","period":"Early Medieval","paper":"Paper I","topics":["Feudalism","Land Grants","Economic History","State Formation"],"type":"debate","upsc_tip":"Present R.S. Sharma's thesis first, then Chattopadhyaya's critique. Conclude with a nuanced position — land grants had feudal elements but context was different from Europe.","positions":[{"historian_name":"R.S. Sharma","stance":"Indian Feudalism Existed","key_work":"Indian Feudalism (1965)","argument":"Land grants to Brahmanas and officials led to decentralization of power, decline of trade, peasant serfdom and forced labour — paralleling European feudalism structurally.","school":"Marxist"},{"historian_name":"D.N. Jha","stance":"Modified Feudalism Model","key_work":"Economy and Society in Early Medieval India (1980)","argument":"Supports feudalism thesis but emphasizes the role of surplus extraction and agrarian expansion as the driving force, not simply political decentralization.","school":"Marxist"},{"historian_name":"B.D. Chattopadhyaya","stance":"Against Simple Feudalism Model","key_work":"The Making of Early Medieval India (1994)","argument":"Early medieval period saw state formation and integration, not feudal fragmentation. Land grants expanded agriculture and created new social formations rather than serfdom.","school":"Revisionist"},{"historian_name":"Harbans Mukhia","stance":"Feudalism Inapplicable","key_work":"Was There Feudalism in Indian History? (1981)","argument":"European feudalism was a specific historical category rooted in serfdom and juridical compulsion. Indian peasants were not serfs — the term cannot be applied mechanically.","school":"Revisionist"}]},{"title":"18th Century Debate: Decline or Decentralization?","period":"18th Century / Early Modern","paper":"Paper I","topics":["Mughal Decline","18th Century","Regional Kingdoms","Economic History"],"type":"debate","upsc_tip":"UPSC frequently asks to 'characterize the 18th century.' Present the old decline thesis, then the revisionist view of Muzaffar Alam and C.A. Bayly. A balanced answer scores well.","positions":[{"historian_name":"Jadunath Sarkar","stance":"Age of Decline and Chaos","key_work":"Fall of the Mughal Empire (1932)","argument":"The 18th century was marked by political anarchy, economic collapse, and moral degradation following Aurangzeb's bigoted policies and weak successors.","school":"Colonial/Nationalist"},{"historian_name":"Muzaffar Alam","stance":"Decentralization, Not Decline","key_work":"The Crisis of Empire in Mughal North India (1986)","argument":"The 18th century saw transfer of power to regional successor states — Awadh, Bengal, Hyderabad — which were not mere breakdowns but capable, prosperous polities.","school":"Revisionist"},{"historian_name":"C.A. Bayly","stance":"Economic Resilience and Bazaar Economy","key_work":"Rulers, Townsmen and Bazaars (1983)","argument":"Indian merchant communities and bazaar economies flourished in the 18th century. The period saw vibrant commercial activity, contradicting the decline narrative.","school":"Cambridge School"},{"historian_name":"Satish Chandra","stance":"Structural Crisis of the Jagirdari System","key_work":"Parties and Politics at the Mughal Court (1959)","argument":"The Mughal decline was structural — the jagirdari crisis (more jagirdars than available jagirs) made the empire fiscally unviable regardless of individual rulers.","school":"Nationalist"}]},{"title":"Nature of the Revolt of 1857","period":"Modern India","paper":"Paper II","topics":["1857 Revolt","Nationalism","Colonial Resistance"],"type":"debate","upsc_tip":"Classic three-way debate — Mutiny thesis vs War of Independence vs peasant/subaltern interpretation. Always cite all three and give a weighted conclusion favoring the multi-causal, proto-nationalist view.","positions":[{"historian_name":"John Lawrence / T.R. Holmes","stance":"Sepoy Mutiny — Military Grievance Only","key_work":"A History of the Indian Mutiny (1883)","argument":"The revolt was essentially a mutiny of disaffected soldiers over immediate grievances like the greased cartridge issue, with no broader nationalist consciousness.","school":"Colonial"},{"historian_name":"V.D. Savarkar","stance":"First War of Indian Independence","key_work":"The Indian War of Independence 1857 (1909)","argument":"The revolt was a planned, coordinated uprising of Hindu and Muslim soldiers and civilians united by a common goal of overthrowing British rule — a genuine nationalist war.","school":"Nationalist"},{"historian_name":"S.N. Sen","stance":"Began as Mutiny, Became Something More","key_work":"Eighteen Fifty-Seven (1957)","argument":"Started as a military mutiny but took on aspects of a popular revolt in certain regions. It was neither purely a mutiny nor a full war of independence.","school":"Nationalist"},{"historian_name":"Rudrangshu Mukherjee","stance":"Subaltern / Peasant Revolt Dimension","key_work":"Awadh in Revolt (1984)","argument":"In Awadh, the revolt was fundamentally a peasant uprising against dispossession by British annexation — the subaltern dimension is as important as the military one.","school":"Subaltern"}]},{"title":"Aryan Origin Debate","period":"Ancient India","paper":"Paper I","topics":["Aryans","Vedic Period","Indus Valley","Migration"],"type":"debate","upsc_tip":"UPSC asks this repeatedly. Present the Invasion theory, Migration theory, and Indigenous origin theory. Cite archaeological and linguistic evidence. Avoid taking extreme positions.","positions":[{"historian_name":"Max Muller","stance":"Aryan Invasion Theory","key_work":"History of Ancient Sanskrit Literature (1859)","argument":"Aryans were a racially distinct group who invaded India around 1500 BCE, destroyed the Harappan civilization, and imposed their language and culture on indigenous people.","school":"Colonial"},{"historian_name":"R.S. Sharma","stance":"Modified Migration Theory","key_work":"Advent of the Aryans in India (1999)","argument":"Aryans migrated into India in waves rather than a single invasion. Archaeological evidence from Painted Grey Ware culture supports this gradual migration thesis.","school":"Marxist"},{"historian_name":"B.B. Lal","stance":"Indigenous Origin / Out of India Theory","key_work":"The Homeland of the Aryans (2005)","argument":"The Aryans were indigenous to India and the Vedic civilization was a continuation of the Harappan. The so-called 'invasion' has no archaeological evidence.","school":"Revisionist"},{"historian_name":"Romila Thapar","stance":"Multiple Migrations, Not Invasion","key_work":"Early India: From Origins to AD 1300 (2002)","argument":"The term 'Aryan' refers to a linguistic group, not a race. Multiple small migrations occurred over centuries; there was no dramatic invasion or conquest.","school":"Nationalist"}]},{"title":"Decline of the Harappan Civilization","period":"Ancient India","paper":"Paper I","topics":["Indus Valley","Harappan","Decline","Archaeology"],"type":"debate","upsc_tip":"Multi-causal answer is best. Mention each theory briefly — ecological, invasion, internal decay. Conclude with the current consensus: ecological factors + internal transformation, not sudden collapse.","positions":[{"historian_name":"Mortimer Wheeler","stance":"Aryan Invasion Destroyed Harappa","key_work":"The Indus Civilization (1953)","argument":"Skeletal remains at Mohenjodaro indicate massacre. Aryan invaders destroyed the Harappan cities — 'Indra stands convicted' as the destroyer of forts mentioned in Vedas.","school":"Colonial"},{"historian_name":"Robert Raikes","stance":"Ecological/Flood Disaster","key_work":"Water, Weather and Prehistory (1967)","argument":"Tectonic activity caused the Indus to flood repeatedly, making cities uninhabitable. Ecological disaster, not invasion, ended the civilization.","school":"Environmental History"},{"historian_name":"Shereen Ratnagar","stance":"Internal Decay and Trade Collapse","key_work":"Trading Encounters (2004)","argument":"Collapse of long-distance trade networks with Mesopotamia undermined the urban economy. Internal contradictions and administrative breakdown caused decline.","school":"Economic History"}]},{"title":"Nature of the Mauryan State","period":"Ancient India","paper":"Paper I","topics":["Mauryan Empire","State Formation","Administration","Arthashastra"],"type":"debate","upsc_tip":"Was it a centralized despotism or a decentralized welfare state? Cite Romila Thapar vs older colonial historians. Arthashastra vs Ashokan edicts give contrasting pictures — use both.","positions":[{"historian_name":"D.D. Kosambi","stance":"Centralized Class State","key_work":"An Introduction to the Study of Indian History (1956)","argument":"The Mauryan state was a class instrument serving the interests of the ruling elite, extracting surplus from peasants through a highly centralized bureaucratic machinery.","school":"Marxist"},{"historian_name":"Romila Thapar","stance":"Segmentary State with Welfare Orientation","key_work":"Asoka and the Decline of the Mauryas (1961)","argument":"The Mauryan state was not uniformly centralized. Ashoka's Dhamma represented a genuine welfare ideology that sought to legitimize authority through moral governance.","school":"Nationalist"},{"historian_name":"A.L. Basham","stance":"Benevolent Despotism","key_work":"The Wonder That Was India (1954)","argument":"The Mauryan state under Ashoka was a benevolent despotism — highly organized administration guided by Dhamma (righteousness) rather than mere coercion.","school":"Liberal"}]},{"title":"Ashoka's Dhamma: Religious Policy or Political Tool?","period":"Ancient India","paper":"Paper I","topics":["Ashoka","Dhamma","Buddhism","Mauryan Empire"],"type":"debate","upsc_tip":"Excellent topic to cite multiple historians. Was Dhamma genuinely Buddhist or a syncretic imperial ideology? Thapar's view of Dhamma as a state policy is most UPSC-friendly.","positions":[{"historian_name":"Romila Thapar","stance":"Dhamma as State Policy, Not Personal Buddhism","key_work":"Asoka and the Decline of the Mauryas (1961)","argument":"Dhamma was not Buddhism per se but a syncretic moral code designed to integrate diverse communities under Mauryan rule — a political ideology serving imperial unity.","school":"Nationalist"},{"historian_name":"B.G. Gokhale","stance":"Dhamma as Genuine Buddhist Commitment","key_work":"Asoka Maurya (1966)","argument":"Ashoka underwent a genuine personal conversion after Kalinga. His Dhamma was sincere Buddhist ethics translated into public policy, not mere political expediency.","school":"Liberal"},{"historian_name":"Vincent Smith","stance":"Dhamma Led to Imperial Weakness","key_work":"Asoka: The Buddhist Emperor of India (1901)","argument":"Ashoka's pacifist Dhamma weakened the military capacity of the empire, contributing to its rapid disintegration after his death.","school":"Colonial"}]},{"title":"Nature of the Bhakti Movement","period":"Medieval India","paper":"Paper I","topics":["Bhakti Movement","Religion","Social Reform","Medieval"],"type":"debate","upsc_tip":"Was Bhakti a social reform movement challenging caste, or a Hindu revivalist response to Islam? Present both. R.C. Majumdar vs D.N. Lorenzen is a key contrast.","positions":[{"historian_name":"R.C. Majumdar","stance":"Hindu Revivalism in Response to Islam","key_work":"History and Culture of the Indian People (1960)","argument":"Bhakti arose primarily as a defensive Hindu response to the challenge of Islam, seeking to purify and revive Hinduism against external pressure.","school":"Nationalist"},{"historian_name":"D.N. Lorenzen","stance":"Bhakti Was Independent of Islam","key_work":"Who Invented Hinduism? (2006)","argument":"Bhakti had deep roots in Tamil Alvars and Nayanmars centuries before Islamic arrival. It was an autonomous devotional tradition, not a reaction to Islam.","school":"Revisionist"},{"historian_name":"Romila Thapar","stance":"Bhakti as Social Protest Against Brahmanical Order","key_work":"A History of India Vol I (1966)","argument":"Bhakti challenged the hierarchical varna-jati system and Brahmanical orthodoxy, giving voice to lower castes and women — a genuine social protest movement.","school":"Marxist"},{"historian_name":"Charlotte Vaudeville","stance":"Nirguna Bhakti as Syncretic Tradition","key_work":"A Weaver Named Kabir (1993)","argument":"The Nirguna saints like Kabir drew from both Hindu and Islamic Sufi traditions, creating a genuinely syncretic spiritual movement transcending religious boundaries.","school":"Cultural History"}]},{"title":"Nature of the Mughal State","period":"Medieval India","paper":"Paper I","topics":["Mughal Empire","State Formation","Jagirdari","Administration"],"type":"debate","upsc_tip":"Was the Mughal state patrimonial, absolutist, or a composite polity? Cite Irfan Habib for the structural-agrarian approach and Muzaffar Alam for the political economy angle.","positions":[{"historian_name":"Irfan Habib","stance":"Agrarian Crisis Caused Decline","key_work":"The Agrarian System of Mughal India (1963)","argument":"The Mughal state rested on ruthless agrarian exploitation. The jagirdari crisis — more jagirdars than available jagirs — created structural instability leading to inevitable collapse.","school":"Marxist"},{"historian_name":"John F. Richards","stance":"Mughal State as Fiscal-Military Empire","key_work":"The Mughal Empire (1993)","argument":"The Mughal state was a sophisticated fiscal-military empire that effectively integrated diverse regions through standardized revenue systems and a professional army.","school":"Cambridge School"},{"historian_name":"M. Athar Ali","stance":"Composite Nature of Mughal Nobility","key_work":"The Mughal Nobility Under Aurangzeb (1966)","argument":"The Mughal nobility was deliberately multi-ethnic — Turani, Irani, Rajput, Indian Muslim — creating a composite ruling class that was the empire's greatest strength and weakness.","school":"Nationalist"}]},{"title":"Aurangzeb: Religious Bigot or Pragmatic Ruler?","period":"Medieval India","paper":"Paper I","topics":["Aurangzeb","Mughal Empire","Religious Policy","Decline"],"type":"debate","upsc_tip":"Avoid one-sided answers. Audrey Truschke's revisionist view vs traditional nationalist critique. Acknowledge both the Jizya reimposition and his grants to Hindu temples — complexity wins marks.","positions":[{"historian_name":"Jadunath Sarkar","stance":"Religious Bigotry Caused Mughal Decline","key_work":"History of Aurangzib (1912-24)","argument":"Aurangzeb's reimposition of Jizya, temple demolitions, and anti-Hindu policies alienated Rajputs and Marathas, provoking revolts that broke the empire.","school":"Nationalist"},{"historian_name":"Audrey Truschke","stance":"Aurangzeb Was More Complex","key_work":"Aurangzeb: The Life and Legacy of India's Most Controversial King (2017)","argument":"Aurangzeb also granted farmans to Hindu temples, employed more Hindus in his administration than any previous Mughal, and his conflicts were political not purely religious.","school":"Revisionist"},{"historian_name":"Satish Chandra","stance":"Structural Factors More Important Than Religion","key_work":"Medieval India (2007)","argument":"The Mughal decline was caused by the jagirdari crisis, Deccan overextension, and rising Maratha power — Aurangzeb's religious policy was a contributory, not primary, factor.","school":"Nationalist"}]},{"title":"Permanent Settlement: Exploitation or Modernization?","period":"Modern India","paper":"Paper II","topics":["Permanent Settlement","Land Revenue","Colonial Economy","Zamindari"],"type":"debate","upsc_tip":"Cornwallis's intentions vs actual outcomes is the key tension. Cite nationalist historians for exploitation angle, Cambridge school for modernization argument. Both are needed.","positions":[{"historian_name":"R.C. Dutt","stance":"Instrument of Exploitation","key_work":"The Economic History of India (1902)","argument":"Permanent Settlement impoverished Bengal's peasantry by creating a class of absentee zamindars who rack-rented tenants while the colonial state extracted fixed revenue regardless of harvest.","school":"Nationalist"},{"historian_name":"Ranajit Guha","stance":"Colonial Power and Peasant Resistance","key_work":"A Rule of Property for Bengal (1963)","argument":"Permanent Settlement represented a Physiocratic ideology transplanted to Bengal — an attempt to create a landed gentry on English lines that fundamentally failed.","school":"Subaltern"},{"historian_name":"B.B. Chaudhuri","stance":"Zamindari System and Agricultural Stagnation","key_work":"Peasant History of Late Pre-Colonial and Colonial India (2008)","argument":"The settlement created structural conditions for agricultural stagnation — zamindars had no incentive to invest in land improvement, causing long-term rural poverty.","school":"Economic History"}]},{"title":"Drain of Wealth Theory","period":"Modern India","paper":"Paper II","topics":["Economic Impact","Colonial Economy","Drain Theory","Deindustrialization"],"type":"debate","upsc_tip":"Dadabhai Naoroji's foundational thesis vs imperialist counter-arguments vs Cambridge school revision. Always quantify the drain if possible — UPSC appreciates empirical grounding.","positions":[{"historian_name":"Dadabhai Naoroji","stance":"Drain Was the Root Cause of Poverty","key_work":"Poverty and Un-British Rule in India (1901)","argument":"Annual drain of 200-300 million pounds from India to Britain through Home Charges, trade surplus, and profit repatriation was the primary cause of Indian poverty.","school":"Nationalist"},{"historian_name":"R.C. Dutt","stance":"Drain Caused Deindustrialization","key_work":"The Economic History of India (1902)","argument":"The drain was compounded by deliberate deindustrialization — British tariff policies destroyed Indian textiles and crafts, reducing the country to a raw material supplier.","school":"Nationalist"},{"historian_name":"Angus Maddison","stance":"Drain Exists but Magnitude Debated","key_work":"The World Economy: A Millennial Perspective (2001)","argument":"India's share of world GDP fell from 24% in 1700 to 4% by 1950 — a quantifiable measure of colonial extraction, though its exact mechanisms remain contested.","school":"Economic History"}]},{"title":"Safety Valve Theory: Origin of the Indian National Congress","period":"Modern India","paper":"Paper II","topics":["Indian National Congress","Nationalism","British Policy","Congress Formation"],"type":"debate","upsc_tip":"Was Congress created to serve British interests or as a genuine nationalist platform? The Lal-Bal-Pal era discredits the safety valve thesis. Cite Bipin Chandra for the nationalist view.","positions":[{"historian_name":"Lala Lajpat Rai","stance":"Congress Was a British Safety Valve","key_work":"Young India (1916)","argument":"Congress was founded by A.O. Hume with British consent to serve as a safety valve — channeling Indian political energy into constitutional, harmless agitation to prevent revolution.","school":"Nationalist"},{"historian_name":"Bipin Chandra","stance":"Congress Represented Genuine Nationalist Aspirations","key_work":"The Rise and Growth of Economic Nationalism in India (1966)","argument":"Congress was the product of genuine nationalist consciousness among the educated middle class, not a British creation. Its economic critique of colonialism was sophisticated and real.","school":"Nationalist"},{"historian_name":"Anil Seal","stance":"Congress as Elite Competition for Jobs","key_work":"The Emergence of Indian Nationalism (1968)","argument":"Early Congress represented the educated Indian elite competing with the British and each other for administrative positions and political influence — not idealist nationalism.","school":"Cambridge School"}]},{"title":"Gandhian Nationalism: Mass Movement or Elite Control?","period":"Modern India","paper":"Paper II","topics":["Gandhi","Nationalism","Mass Mobilization","Non-Cooperation"],"type":"debate","upsc_tip":"Subaltern school critique of Gandhi is important — Shahid Amin's work on Chauri Chaura. Also contrast Gandhi's methods with the Extremists and socialists within Congress.","positions":[{"historian_name":"Bipin Chandra","stance":"Gandhi Transformed Nationalism into Mass Movement","key_work":"India's Struggle for Independence (1989)","argument":"Gandhi's genius lay in mobilizing the peasantry, giving nationalism a religious idiom the masses could connect with, transforming Congress from an elite club to a mass organization.","school":"Nationalist"},{"historian_name":"Shahid Amin","stance":"Subaltern Agency Beyond Gandhi's Control","key_work":"Event, Metaphor, Memory: Chauri Chaura 1922-1992 (1995)","argument":"The peasant masses had their own agenda distinct from Gandhian nationalism. Chauri Chaura shows how subaltern violence exceeded the boundaries Gandhi tried to set.","school":"Subaltern"},{"historian_name":"Sumit Sarkar","stance":"Gandhi's Nationalism Had Class Limits","key_work":"Modern India 1885-1947 (1983)","argument":"Gandhi's movement consistently protected bourgeois and zamindari interests. His calls to halt movements whenever lower-class radicalism emerged revealed structural conservatism.","school":"Marxist"},{"historian_name":"Judith Brown","stance":"Gandhi as Skilled Political Broker","key_work":"Gandhi: Prisoner of Hope (1989)","argument":"Gandhi was a pragmatic political organizer who brokered between diverse Indian interests — his apparent inconsistencies were strategic adaptations, not ideological failures.","school":"Cambridge School"}]},{"title":"Causes of Partition of India 1947","period":"Modern India","paper":"Paper II","topics":["Partition","Communalism","Muslim League","Transfer of Power"],"type":"debate","upsc_tip":"Three main schools: British responsibility (divide and rule), Muslim League separatism, and Congress failures. Ayesha Jalal's argument about Jinnah's negotiating tactic is important.","positions":[{"historian_name":"Ayesha Jalal","stance":"Jinnah Wanted Leverage, Not Partition","key_work":"The Sole Spokesman: Jinnah, the Muslim League and the Demand for Pakistan (1985)","argument":"Jinnah used the Pakistan demand as a bargaining chip to secure Muslim political rights in a united India. Partition was an unintended outcome of Congress's refusal to share power.","school":"Revisionist"},{"historian_name":"Mushirul Hasan","stance":"Communalism Was Constructed, Not Primordial","key_work":"Legacy of a Divided Nation (1997)","argument":"Hindu-Muslim communal identity was not ancient — it was constructed and sharpened by colonial policies, communal organizations, and political mobilization in the 20th century.","school":"Nationalist"},{"historian_name":"Bipan Chandra","stance":"Communalism as Colonial Ideology","key_work":"Communalism in Modern India (1984)","argument":"Communalism was a bourgeois ideology serving middle-class competition for jobs and power under colonial conditions — not a reflection of genuine religious conflict.","school":"Marxist"}]},{"title":"Subaltern Nationalism: Were Tribal/Peasant Uprisings Proto-Nationalist?","period":"Modern India","paper":"Paper II","topics":["Subaltern","Peasant Movements","Tribal Uprisings","Nationalism"],"type":"debate","upsc_tip":"Ranajit Guha's subaltern school vs mainstream nationalist historians is the key debate. UPSC asks this as 'were these movements backwards-looking or forward-looking?'","positions":[{"historian_name":"Ranajit Guha","stance":"Subaltern Consciousness Was Autonomous","key_work":"Elementary Aspects of Peasant Insurgency in Colonial India (1983)","argument":"Peasant and tribal rebellions had their own logic, consciousness, and politics — they cannot be subsumed under elite nationalist narrative. Their 'backwardness' was their strength.","school":"Subaltern"},{"historian_name":"Eric Stokes","stance":"Local Grievances, Not Nationalism","key_work":"The Peasant and the Raj (1978)","argument":"19th century peasant uprisings were responses to specific local economic dislocations — loss of land, usury, forest rights — not expressions of proto-nationalist consciousness.","school":"Cambridge School"},{"historian_name":"Bipin Chandra","stance":"Part of the Broader Anti-Colonial Movement","key_work":"India's Struggle for Independence (1989)","argument":"Tribal and peasant uprisings, while driven by local grievances, contributed to the tradition of anti-colonial resistance that fed into the national movement.","school":"Nationalist"}]},{"title":"Orientalist-Anglicist Controversy","period":"Modern India","paper":"Paper II","topics":["Education Policy","Colonial Policy","Macaulay","Sanskrit Education"],"type":"debate","upsc_tip":"Key figures: Macaulay (Anglicist) vs H.H. Wilson (Orientalist). The Minute of 1835 is the turning point. Also bring in the postcolonial critique — Macaulay's education created a class 'Indian in blood but English in taste.'","positions":[{"historian_name":"Thomas Macaulay","stance":"English Education is Superior","key_work":"Minute on Indian Education (1835)","argument":"Western scientific education in English would create a class of educated Indians who could assist in colonial administration — Indian classical learning had no scientific value.","school":"Colonial"},{"historian_name":"H.H. Wilson","stance":"Oriental Learning Must Be Preserved","key_work":"Orientalist Position Papers","argument":"Sanskrit and Arabic classical learning embodied India's intellectual heritage. British policy should support indigenous learning to understand and govern India effectively.","school":"Colonial"},{"historian_name":"Gauri Viswanathan","stance":"English Literature as Colonial Tool","key_work":"Masks of Conquest (1989)","argument":"English literary education in India was a deliberate tool of cultural colonialism — using Shakespeare and Milton to legitimize British rule and discredit Indian civilization.","school":"Postcolonial"}]},{"title":"Causes of World War I","period":"World History","paper":"Paper II","topics":["World War I","Imperialism","Nationalism","Alliance System"],"type":"debate","upsc_tip":"Fischer Controversy is the most important historiographical debate on WWI. Germany's war guilt (Article 231) vs the revisionist view that all powers share responsibility.","positions":[{"historian_name":"Fritz Fischer","stance":"Germany Primarily Responsible","key_work":"Germany's Aims in the First World War (1961)","argument":"Germany deliberately used the July Crisis to launch an aggressive war aimed at European hegemony. The September Program shows premeditated expansionist goals.","school":"Revisionist"},{"historian_name":"A.J.P. Taylor","stance":"War by Timetable — No Single Culprit","key_work":"War by Timetable (1969)","argument":"WWI was the result of rigid military mobilization plans (especially the Schlieffen Plan) that left no room for diplomatic solutions — a catastrophic accident, not a planned war.","school":"Revisionist"},{"historian_name":"Christopher Clark","stance":"Sleepwalkers — Shared Responsibility","key_work":"The Sleepwalkers: How Europe Went to War in 1914 (2012)","argument":"All major powers stumbled into war through miscalculation, poor communication, and entangled alliances. Serbia's role in the assassination was also significant.","school":"Revisionist"}]},{"title":"French Revolution: Bourgeois Revolution or Political Crisis?","period":"World History","paper":"Paper II","topics":["French Revolution","Bourgeoisie","Class Struggle","Enlightenment"],"type":"debate","upsc_tip":"Classic Marxist vs revisionist debate in world history. UPSC asks about causes and character — mention both the social history approach and the political/contingency approach.","positions":[{"historian_name":"Albert Soboul","stance":"Classic Bourgeois Revolution","key_work":"The French Revolution 1787-1799 (1962)","argument":"The Revolution was a classic bourgeois revolution — the rising capitalist class overthrew the feudal aristocracy to establish conditions for capitalist development.","school":"Marxist"},{"historian_name":"Alfred Cobban","stance":"No Evidence of Bourgeois Revolution","key_work":"The Social Interpretation of the French Revolution (1964)","argument":"The 'revolutionary bourgeoisie' was actually a declining class of office-holders, not rising capitalists. The Marxist social interpretation is unsupported by evidence.","school":"Revisionist"},{"historian_name":"William Doyle","stance":"Political and Ideological Crisis","key_work":"Origins of the French Revolution (1980)","argument":"The Revolution had multiple causes — fiscal crisis of the state, aristocratic reaction, Enlightenment ideas, and contingent political failures — not reducible to class conflict.","school":"Revisionist"}]},{"title":"Russian Revolution 1917: Inevitable or Contingent?","period":"World History","paper":"Paper II","topics":["Russian Revolution","Bolshevik","Marxism","Lenin"],"type":"debate","upsc_tip":"Was the October Revolution a genuine mass revolution or a Bolshevik coup? Cold War era historians differ sharply. Cite Sheila Fitzpatrick for the social history approach.","positions":[{"historian_name":"Leon Trotsky","stance":"Inevitable Product of Class Struggle","key_work":"History of the Russian Revolution (1932)","argument":"The Revolution was the inevitable result of capitalist contradictions, imperialist war, and the revolutionary consciousness of the working class led by the Bolshevik Party.","school":"Marxist"},{"historian_name":"Richard Pipes","stance":"Bolshevik Coup, Not Mass Revolution","key_work":"The Russian Revolution (1990)","argument":"October 1917 was a coup by a disciplined minority party (Bolsheviks) that exploited the chaos of WWI — it did not represent genuine mass revolutionary consciousness.","school":"Liberal"},{"historian_name":"Sheila Fitzpatrick","stance":"Revolution from Below with Bolshevik Direction","key_work":"The Russian Revolution (1982)","argument":"Worker and peasant grievances created genuine revolutionary energy from below. The Bolsheviks channeled and directed this energy — neither pure coup nor pure mass revolution.","school":"Social History"}]},{"title":"Imperialism: Economic Necessity or Political Choice?","period":"World History","paper":"Paper II","topics":["Imperialism","Colonialism","Neo-Imperialism","Economic History"],"type":"debate","upsc_tip":"Lenin vs Hobson vs the cultural imperialism approach. UPSC asks about causes of neo-imperialism — economic factors must be mentioned but do not reduce it to economics alone.","positions":[{"historian_name":"J.A. Hobson","stance":"Imperialism as Economic Necessity","key_work":"Imperialism: A Study (1902)","argument":"Imperialism resulted from under-consumption at home — capitalists unable to sell goods or invest profitably in domestic markets exported capital to colonies.","school":"Liberal"},{"historian_name":"V.I. Lenin","stance":"Imperialism as Highest Stage of Capitalism","key_work":"Imperialism, the Highest Stage of Capitalism (1917)","argument":"Finance capital and monopoly capitalism inevitably lead to territorial imperialism — dividing the world among great powers creates inter-imperialist rivalry and war.","school":"Marxist"},{"historian_name":"Ronald Robinson and John Gallagher","stance":"Free Trade Imperialism — Continuity Not Break","key_work":"Africa and the Victorians (1961)","argument":"There was no sharp break between free trade and formal imperialism. Britain expanded informal influence through trade throughout the 19th century — formal annexation came only when informal control failed.","school":"Cambridge School"}]},{"title":"Gandhi vs Ambedkar: Caste Abolition Debate","period":"Modern India","paper":"Paper II","topics":["Caste","Gandhi","Ambedkar","Social Reform","Dalit"],"type":"debate","upsc_tip":"The Poona Pact 1932 is the focal point. Gandhi's varnashrama vs Ambedkar's annihilation of caste. UPSC may ask about approaches to social justice — this debate is directly relevant.","positions":[{"historian_name":"B.R. Ambedkar","stance":"Caste Must Be Annihilated","key_work":"Annihilation of Caste (1936)","argument":"Caste is a graded system of inequality rooted in Hindu scripture. It cannot be reformed — it must be destroyed. Gandhi's Harijan uplift program patronized Dalits without challenging the system.","school":"Dalit"},{"historian_name":"M.K. Gandhi","stance":"Reform Varnashrama, Eliminate Untouchability","key_work":"Hind Swaraj (1909)","argument":"Varnashrama (caste by occupation, not birth) is consistent with Indian civilization. The evil is untouchability, not caste itself. Reform from within, not destruction.","school":"Nationalist"},{"historian_name":"Gail Omvedt","stance":"Ambedkar's Analysis Was Correct","key_work":"Dalit Visions (1995)","argument":"Historical evidence vindicates Ambedkar — post-independence India shows caste persists because Gandhi's reformist approach left its structural basis intact.","school":"Dalit"}]},{"title":"Chola State: Segmentary or Centralized?","period":"Early Medieval","paper":"Paper I","topics":["Chola Empire","State Formation","South India","Local Government"],"type":"debate","upsc_tip":"Burton Stein's segmentary state model is frequently referenced in UPSC. Contrast with Noboru Karashima's critique. The Uttaramerur inscriptions are key evidence for local autonomy.","positions":[{"historian_name":"Burton Stein","stance":"Segmentary State Model","key_work":"Peasant State and Society in Medieval South India (1980)","argument":"The Chola state was a segmentary state — ritual sovereignty at the center but actual political and economic power exercised by local peasant assemblies (nadus) and brahmadeyas.","school":"Social History"},{"historian_name":"Noboru Karashima","stance":"Cholas Were Centralized and Bureaucratic","key_work":"South Indian History and Society (1984)","argument":"Epigraphic evidence shows Chola rulers exercised real administrative control through officials, tax collection, and military campaigns — not a ritual figurehead.","school":"Revisionist"},{"historian_name":"R. Champakalakshmi","stance":"Temple Economy as Integrating Mechanism","key_work":"Trade, Ideology and Urbanization (1996)","argument":"Chola temples served as economic institutions integrating local societies — not merely ritual centers. Temple economy explains both local autonomy and imperial integration.","school":"Economic History"}]},{"title":"Akbar's Religious Policy: Sulh-i-Kul and Din-i-Ilahi","period":"Medieval India","paper":"Paper I","topics":["Akbar","Mughal Empire","Religious Policy","Sulh-i-Kul"],"type":"debate","upsc_tip":"Was Din-i-Ilahi a genuine religion or a political tool? Most historians see it as political syncretism. Thapar's composite culture argument is most UPSC-friendly.","positions":[{"historian_name":"Vincent Smith","stance":"Din-i-Ilahi Was Akbar's Personal Cult","key_work":"Akbar the Great Mogul (1917)","argument":"Akbar's religious experiments were megalomaniacal — placing himself as the center of a new religion was an exercise in autocratic vanity, not genuine spirituality.","school":"Colonial"},{"historian_name":"Sri Ram Sharma","stance":"Sulh-i-Kul as Political Strategy","key_work":"The Religious Policy of the Mughal Emperors (1940)","argument":"Akbar's policy of Sulh-i-Kul (peace with all) was a pragmatic political tool to integrate diverse communities — Hindu Rajputs, Shia nobility, Sunnis — under Mughal authority.","school":"Nationalist"},{"historian_name":"Iqtidar Alam Khan","stance":"Genuine Composite Culture","key_work":"Akbar's Personality Traits and World Outlook (1975)","argument":"Akbar's religious policy reflected a genuine intellectual curiosity and commitment to creating a composite Indo-Islamic culture — not merely political calculation.","school":"Nationalist"}]},{"title":"Economic Impact of British Rule: De-industrialization","period":"Modern India","paper":"Paper II","topics":["Deindustrialization","Colonial Economy","Textiles","Industrial History"],"type":"debate","upsc_tip":"UPSC asks about deindustrialization repeatedly. Tirthankar Roy's revisionist argument is important — distinguish between decline of handicrafts vs growth of modern industry.","positions":[{"historian_name":"R.C. Dutt","stance":"British Policies Destroyed Indian Industry","key_work":"The Economic History of India (1902)","argument":"Discriminatory tariff policies protecting British textiles while flooding India with machine-made goods systematically destroyed India's world-famous cotton weaving industry.","school":"Nationalist"},{"historian_name":"Morris David Morris","stance":"Economic Growth Under British Rule","key_work":"The Emergence of an Industrial Labor Force in India (1965)","argument":"British rule created railways, modern industry, and a wage labor force — the decline of handicrafts was offset by growth in modern sectors. Net economic impact was mixed.","school":"Liberal"},{"historian_name":"Tirthankar Roy","stance":"Globalization Caused Structural Change, Not Destruction","key_work":"The Economic History of India 1857-1947 (2000)","argument":"What appears as deindustrialization was actually structural transformation — some crafts declined while others adapted and survived. The process was more nuanced than nationalist accounts suggest.","school":"Revisionist"}]},{"title":"Social Reform Movements: Reform or Reinforcement of Patriarchy?","period":"Modern India","paper":"Paper II","topics":["Social Reform","Women's History","Sati","Widow Remarriage"],"type":"debate","upsc_tip":"Feminist historians critique Ram Mohan Roy and other reformers for paternalistic, elite-driven reform. Lata Mani's work is key — women were the site, not subject of reform.","positions":[{"historian_name":"Charles Heimsath","stance":"Reform as Progressive Modernization","key_work":"Indian Nationalism and Hindu Social Reform (1964)","argument":"19th century social reformers genuinely challenged oppressive customs — the abolition of sati, widow remarriage, and women's education were progressive achievements.","school":"Liberal"},{"historian_name":"Lata Mani","stance":"Women as Site, Not Subject of Reform","key_work":"Contentious Traditions: The Debate on Sati in Colonial India (1998)","argument":"The sati debate was really between British colonialists and Indian men about the nature of Hindu tradition — women's voices were absent. Reform was conducted over women, not for them.","school":"Feminist"},{"historian_name":"Tanika Sarkar","stance":"Reform Had Both Progressive and Conservative Elements","key_work":"Hindu Wife, Hindu Nation (2001)","argument":"Social reform empowered women in some respects while simultaneously constructing new forms of domesticity that confined women to the home as keepers of cultural tradition.","school":"Feminist"}]},{"title":"Rise of Buddhism and Jainism: Social Protest or Spiritual Reform?","period":"Ancient India","paper":"Paper I","topics":["Buddhism","Jainism","Social History","Varna System"],"type":"debate","upsc_tip":"Were Buddhism and Jainism reactions against Brahmanical varna system or genuine spiritual movements? D.D. Kosambi's social protest angle vs traditional religious history. Both needed.","positions":[{"historian_name":"D.D. Kosambi","stance":"Social Protest Against Brahmanical Order","key_work":"An Introduction to the Study of Indian History (1956)","argument":"Buddhism and Jainism arose as protest movements of the Kshatriya class and trading communities against Brahmanical ritual monopoly and the economic costs of Vedic sacrifices.","school":"Marxist"},{"historian_name":"Romila Thapar","stance":"Response to Urbanization and New Economy","key_work":"A History of India Vol I (1966)","argument":"The rise of Mahajanapadas, urban centers, and a money economy created new social groups (merchants, artisans) who found the heterodox traditions more compatible with their worldview.","school":"Social History"},{"historian_name":"A.L. Basham","stance":"Genuine Spiritual Reform","key_work":"The Wonder That Was India (1954)","argument":"While social factors played a role, Buddhism and Jainism represented genuine spiritual responses to the philosophical limitations of Vedic religion — their ethical emphasis was their core.","school":"Liberal"}]},{"title":"Cold War Origins: Who Was Responsible?","period":"World History","paper":"Paper II","topics":["Cold War","USA","USSR","Post-WWII"],"type":"debate","upsc_tip":"Three schools: orthodox (Soviet aggression), revisionist (American imperialism), post-revisionist (shared responsibility). Post-revisionist is safest for UPSC.","positions":[{"historian_name":"Arthur Schlesinger Jr.","stance":"Soviet Expansionism Caused Cold War","key_work":"Origins of the Cold War (1967)","argument":"Soviet expansionism in Eastern Europe and Stalin's inherently aggressive ideology forced the USA to respond defensively — the USSR bears primary responsibility.","school":"Liberal"},{"historian_name":"William Appleman Williams","stance":"American Economic Imperialism","key_work":"The Tragedy of American Diplomacy (1959)","argument":"American capitalism required open markets globally — US 'Open Door' imperialism threatened Soviet security and forced a defensive Soviet response in Eastern Europe.","school":"Revisionist"},{"historian_name":"John Lewis Gaddis","stance":"Post-Revisionist: Shared Responsibility with Soviet Primacy","key_work":"The Cold War: A New History (2005)","argument":"Both powers contributed to Cold War tensions, but Stalin's decisions — especially the Berlin Blockade and Korean War support — were more destabilizing than American actions.","school":"Revisionist"}]},{"title":"Indus Valley Civilization: Urban Planning and Social Organization","period":"Ancient India","paper":"Paper I","topics":["Indus Valley","Urban History","Social History","Archaeology"],"type":"topic","upsc_tip":"Focus on the unique features — absence of monumental temples/palaces, great bath, granaries, standardized weights. Shereen Ratnagar's work on trade is important for economic aspects.","positions":[{"historian_name":"Shereen Ratnagar","stance":"Trade-Based Urban Economy","key_work":"Encounters: The Westerly Trade of the Harappan Civilization (1981)","argument":"Harappan urbanism was sustained by long-distance trade with Mesopotamia and Central Asia. The civilization's standardized weights and seals reflect a sophisticated mercantile economy.","school":"Economic History"},{"historian_name":"Jonathan Mark Kenoyer","stance":"Craft Production and Elite Control","key_work":"Ancient Cities of the Indus Valley Civilization (1998)","argument":"Harappan cities were organized around specialized craft production — bead-making, shell-working, metallurgy — controlled by merchant elites who maintained inter-city networks.","school":"Archaeological"},{"historian_name":"Mortimer Wheeler","stance":"Strong Centralized State","key_work":"The Indus Civilization (1953)","argument":"The remarkable uniformity of Harappan material culture — standardized bricks, weights, city planning — suggests a strong centralized state authority.","school":"Colonial"}]},{"title":"Industrial Revolution: Why Britain First?","period":"World History","paper":"Paper II","topics":["Industrial Revolution","Britain","Economic History","Technology"],"type":"debate","upsc_tip":"UPSC asks about causes of Industrial Revolution in Britain. Do not list causes mechanically — show you know the debate: resources vs institutions vs geography vs colonialism.","positions":[{"historian_name":"Eric Hobsbawm","stance":"Colonial Markets and Capital Drove Industrialization","key_work":"Industry and Empire (1968)","argument":"British industrialization was driven by colonial markets for cotton textiles and capital accumulated through colonial trade. Empire was not incidental but central to industrialization.","school":"Marxist"},{"historian_name":"Joel Mokyr","stance":"Enlightenment Culture and Applied Science","key_work":"The Enlightened Economy (2009)","argument":"Britain industrialized first because its culture of 'useful knowledge' — the application of science to production — was uniquely developed through the Enlightenment.","school":"Cultural History"},{"historian_name":"Kenneth Pomeranz","stance":"Coal Geography and Colonial Cotton Enabled Divergence","key_work":"The Great Divergence (2000)","argument":"Before 1800, China and Britain had similar economic levels. Britain's unique advantage was coal deposits near industrial centers and access to American cotton — not culture or institutions.","school":"Social History"}]},{"title":"Nature of the Vijayanagara Empire","period":"Medieval India","paper":"Paper I","topics":["Vijayanagara","South India","Hindu Resistance","State Formation"],"type":"debate","upsc_tip":"Was Vijayanagara founded as a Hindu bulwark against Islam? Burton Stein and Phillip Wagoner challenge this nationalist narrative. Mention the Nayankara system as administrative innovation.","positions":[{"historian_name":"Robert Sewell","stance":"Hindu Kingdom Against Muslim Invasion","key_work":"A Forgotten Empire (1900)","argument":"Vijayanagara was founded as a bulwark of Hindu civilization against Muslim sultanates — its survival preserved South Indian Hindu culture for two centuries.","school":"Colonial"},{"historian_name":"Burton Stein","stance":"Peasant State with Ritual Sovereignty","key_work":"Vijayanagara (1989)","argument":"Vijayanagara was not a unified Hindu kingdom but a segmentary state integrating diverse warrior chiefs through ritual sovereignty and military alliances.","school":"Social History"},{"historian_name":"Phillip Wagoner","stance":"Hybrid Indo-Islamic Culture","key_work":"Tidings of the King (1993)","argument":"Vijayanagara rulers adopted Persianate court culture, Islamic dress, and administrative terminology — the empire was culturally hybrid, not a defender of Hindu purity.","school":"Cultural History"}]},{"title":"Sufism: Spiritual Movement or Tool of Islamic Expansion?","period":"Medieval India","paper":"Paper I","topics":["Sufism","Islam","Medieval India","Syncretism","Conversions"],"type":"debate","upsc_tip":"Did Sufism facilitate mass conversions to Islam? Richard Eaton vs nationalist historians. Eaton's argument about social conversion through Sufi shrines is well-regarded by UPSC examiners.","positions":[{"historian_name":"Richard Eaton","stance":"Sufis as Social Pioneers in Frontier Zones","key_work":"The Rise of Islam and the Bengal Frontier (1993)","argument":"Islam spread in Bengal not through force or Sufi preaching alone but because Sufi shrines became centers of social organization in newly cultivated frontier areas.","school":"Social History"},{"historian_name":"Simon Digby","stance":"Sufi Charisma and Personal Devotion","key_work":"Sufis and Soldiers in Awrangzeb's Deccan (2001)","argument":"Individual Sufi saints attracted followers through personal charisma and spiritual authority — the personal devotional bond between shaikh and murid was the primary driver.","school":"Cultural History"},{"historian_name":"Aziz Ahmad","stance":"Sufism as Part of Islamic Expansion","key_work":"Studies in Islamic Culture in the Indian Environment (1964)","argument":"Sufi orders were conscious agents of Islamic expansion — their khanqahs served as centers of Islamic culture that gradually assimilated local populations into Islamic practice.","school":"Islamic History"}]},{"title":"Caste and the Colonial Census","period":"Modern India","paper":"Paper II","topics":["Caste","Colonial Policy","Census","Social History"],"type":"debate","upsc_tip":"Nicholas Dirks's argument that colonialism hardened caste is very important for UPSC. Contrast with the view that caste was already rigid before colonialism.","positions":[{"historian_name":"Nicholas Dirks","stance":"Colonialism Hardened and Politicized Caste","key_work":"Castes of Mind (2001)","argument":"The colonial census transformed caste from a flexible, locally variable social practice into a rigid, all-India enumerated category — colonialism invented 'caste' as we know it today.","school":"Postcolonial"},{"historian_name":"Susan Bayly","stance":"Caste Was Already Significant Before Colonialism","key_work":"Caste, Society and Politics in India (1999)","argument":"Caste hierarchies and distinctions were already significant in pre-colonial India. Colonialism intensified but did not create caste — the 'colonial invention' thesis overstates the case.","school":"Revisionist"},{"historian_name":"B.R. Ambedkar","stance":"Caste is Brahmanical Oppression, Pre-Colonial","key_work":"Annihilation of Caste (1936)","argument":"Caste is a fundamentally Brahmanical institution rooted in Hindu religious texts — its oppressive character predates colonialism. Colonial focus as cause deflects from this.","school":"Dalit"}]},{"title":"Deccan Policy and Mughal Overextension under Aurangzeb","period":"Medieval India","paper":"Paper I","topics":["Aurangzeb","Deccan Policy","Mughal Decline","Marathas"],"type":"topic","upsc_tip":"Aurangzeb spent 26 years in the Deccan — was this the primary cause of Mughal decline? Most historians say yes, combined with the jagirdari crisis. Irfan Habib's structural analysis is key.","positions":[{"historian_name":"Jadunath Sarkar","stance":"Deccan War Exhausted the Empire","key_work":"History of Aurangzib (1912-24)","argument":"Aurangzeb's obsessive Deccan campaigns for 26 years drained the treasury, stretched military resources, and distracted attention from other threats — the primary cause of decline.","school":"Nationalist"},{"historian_name":"Irfan Habib","stance":"Jagirdari Crisis Was the Structural Cause","key_work":"The Agrarian System of Mughal India (1963)","argument":"The Deccan War was a symptom, not the cause — the fundamental problem was the jagirdari crisis. More jagirdars competed for fixed jagir revenue, making the system fiscally unsustainable.","school":"Marxist"},{"historian_name":"M. Athar Ali","stance":"Noble Factionalism as Political Cause","key_work":"The Mughal Nobility Under Aurangzeb (1966)","argument":"Aurangzeb's religious policy alienated Rajput nobles, while Irani-Turani factional conflicts within the nobility weakened political cohesion — political factors mattered alongside economic ones.","school":"Nationalist"}]}];

async function seedDB() {
  const { createClient } = await import('https://esm.sh/@supabase/supabase-js@2');
  // Use your existing supabase instance if available, otherwise:
  // const sb = createClient(SUPABASE_URL, SUPABASE_ANON_KEY);
  
  // If running in browser on historyoptional.xyz, window.supabase might be available
  // Otherwise paste your URL and key:
  const sb = window.__supabase || supabase; // adjust as needed
  
  let inserted = 0;
  for (const entry of SEED) {
    const { positions, ...debate } = entry;
    const { data, error } = await sb.from('debates').insert(debate).select().single();
    if (error) { console.error('Error:', entry.title, error.message); continue; }
    const posRows = positions.map(p => ({ ...p, debate_id: data.id }));
    await sb.from('positions').insert(posRows);
    inserted++;
    console.log(`✓ ${inserted}/${SEED.length}: ${entry.title}`);
  }
  console.log('Done! Total inserted:', inserted);
}

seedDB();
